import type { Integration } from '../astro.js';

function randomFromArray<T>(list: T[]) {
	return list[Math.floor(Math.random() * list.length)];
}

const categoryIcons = new Map(
	Object.entries({
		frameworks: ['puzzle', 'grid'],
		adapters: ['puzzle', 'grid', 'compress'],
		'css+ui': ['compress', 'grid', 'image', 'resizeImage', 'puzzle'],
		'performance+seo': ['approveUser', 'checkCircle', 'compress', 'robot', 'searchFile', 'sitemap'],
		analytics: ['checkCircle', 'compress', 'searchFile'],
		accessibility: ['approveUser', 'checkCircle'],
		other: ['checkCircle', 'grid', 'puzzle', 'sitemap'],
	}),
);

export function iconForIntegration(integration: Integration) {
	const icons = integration.categories
		.filter((category: string) => categoryIcons.has(category))
		.flatMap((category: string) => categoryIcons.get(category)!);

	return randomFromArray(icons);
}

const iconColors = [
	'#BC52EE',
	'#6D6AF0',
	'#52EEBD',
	'#52B7EE',
	'#52EE55',
	'#B7EE52',
	'#EEBD52',
	'#EE5552',
	'#EE52B7',
	'#858B98',
];

export function colorForIntegration() {
	return randomFromArray(iconColors);
}

interface ParsedI18nUrl {
	locale: string;
	path: string;
}

// NOTE: The parameters have been schema-validated with Zod
export function parseI18nUrl(
	url: string,
	defaultLocale: string,
	locales: Record<string, string>,
	base: string,
): ParsedI18nUrl | undefined {
	if (!url.startsWith(base)) {
		return undefined;
	}

	let s = url.slice(base.length);

	// Handle root URL
	if (!s || s === '/') {
		return { locale: defaultLocale, path: '/' };
	}

	if (s[0] !== '/') {
		s = '/' + s;
	}

	// Get locale from path, e.g.
	// "/en-US/" -> "en-US"
	// "/en-US/foo" -> "en-US"
	const locale = s.split('/')[1];
	if (locale in locales) {
		// "/en-US/foo" -> "/foo"
		let path = s.slice(1 + locale.length);
		if (!path) {
			path = '/';
		}
		return { locale, path };
	}

	return { locale: defaultLocale, path: s };
}

---
interface Props {
	href?: string | undefined;
}
const { href } = Astro.props;
const El = href ? 'a' : 'span';
---

<li class="not-content sl-flex">
	<El class="media-card sl-flex" {href}>
		<div class="media"><slot name="media" /></div>
		<slot />
	</El>
</li>

<style>
	.media-card {
		flex-direction: column;
		border: 1px solid var(--sl-color-gray-5);
		border-radius: 0.5rem;
		overflow: hidden;
		text-decoration: none;
		box-shadow: var(--sl-shadow-sm);
		width: 100%;
	}
	a:hover {
		border-color: var(--sl-color-gray-2);
		background-color: var(--sl-color-gray-7, var(--sl-color-gray-6));
	}

	.media {
		border-bottom: 1px solid var(--sl-color-gray-5);
	}

	.media :global(img) {
		display: block;
		width: 100%;
		height: auto;
		aspect-ratio: 16 / 9;
		object-fit: cover;
	}

	.media-card :global(.title) {
		color: var(--sl-color-white);
		font-weight: 600;
		line-height: var(--sl-line-height-headings);
	}
</style>

---
interface Props {
	light?: boolean;
}
---

<div class="not-content">
	<div class="palette">
		{
			Astro.props.light ? (
				<div class="circle" style="--bg:var(--sl-color-accent)" />
			) : (
				<div class="circle" style="--bg:var(--sl-color-accent-high)" />
			)
		}
		<div style="--bg:var(--sl-color-black)"></div>
		<div style="--bg:var(--sl-color-white)"></div>
		<div style="--bg:var(--sl-color-gray-1)"></div>
		<div style="--bg:var(--sl-color-gray-2)"></div>
		<div style="--bg:var(--sl-color-gray-3)"></div>
		<div style="--bg:var(--sl-color-gray-4)"></div>
		<div style="--bg:var(--sl-color-gray-5)"></div>
		<div style="--bg:var(--sl-color-gray-6)"></div>
		{Astro.props.light && <div style="--bg:var(--sl-color-gray-7)" />}
	</div>
</div>

<style>
	.palette {
		display: grid;
		grid-template-columns: repeat(10, 1fr);
	}
	.palette > * {
		aspect-ratio: 1;
		background-color: var(--bg);
	}

	.circle {
		border-radius: 50%;
	}
</style>

---
import { Tabs, TabItem } from '@astrojs/starlight/components';

const showContentTypeTabs = Astro.slots.has('markdoc');
---

<figure>
	{
		showContentTypeTabs ? (
			<Tabs syncKey="content-type">
				<TabItem label="MDX">
					<slot />
				</TabItem>
				<TabItem label="Markdoc">
					<slot name="markdoc" />
				</TabItem>
			</Tabs>
		) : (
			<slot />
		)
	}
	<div class="preview">
		<figcaption>{Astro.locals.t('component.preview')}</figcaption>
		<div class="preview-content"><slot name="preview" /></div>
	</div>
</figure>

<style>
	:global(.sl-markdown-content) .preview {
		border: 1px solid var(--sl-color-gray-5);
		border-top: none;
		margin-top: 0;
	}

	.preview:only-child {
		border-top: 1px solid var(--sl-color-gray-5);
	}

	figcaption {
		font-size: var(--sl-text-sm);
		font-weight: 600;
		padding: 0.5rem 1rem 0;
	}

	:global(.sl-markdown-content) .preview-content {
		margin-top: 0;
		padding: 1rem;
	}
</style>
